def parse_nested_parens(paren_string: str) -> List[int]:
    """ Input to this function is a string represented multiple groups for nested parentheses separated by spaces.
    For each of the group, output the deepest level of nesting of parentheses.
    E.g. (()()) has maximum two levels of nesting while ((())) has three.

    >>> parse_nested_parens('(()()) ((())) () ((())()())')
    [2, 3, 1, 3]
    """
    def calculate_depth(s: str) -> int:
        stack = []
        for char in s:
            if char == '(':
                stack.append(1)
            elif char == ')':
                if stack:
                    stack.pop()
        return len(stack)

    result = []
    depth_map = {}
    for i in range(len(paren_string) - 1):
        if paren_string[i] == '(':
            depth_map[paren_string[i]] = calculate_depth(paren_string[:i+1])
            if len(result) == 0:
                result.append(depth_map[paren_string[i]])
            else:
                result.append(depth_map[paren_string[i]])
            if depth_map[paren_string[i]] != len(paren_string[i]):
                break
        elif paren_string[i] == ')':
            if i + 1 < len(paren_string):
                depth = depth_map[paren_string[i+1]]
                result.append(depth)
            else:
                result.append(depth_map[paren_string[i+1]])
            break

    return result

