def strange_sort_list(lst):
    """
    Given list of integers, return list in strange order.
    Strange sorting, is when you start with the minimum value,
    then maximum of the remaining integers, then minimum and so on.
    """
    if not lst:
        return lst

    min_val = min(lst)
    max_val = max(lst)

    # Create a list containing both the min and max values
    sorted_order = [min_val, max_val]

    # Iterate through the rest of the list elements
    for item in lst:
        if item < min_val:
            # Find the index of the first element larger than current item
            for i, x in enumerate(sorted_order):
                if x >= item:
                    # Swap the current element with the next in the sorted order
                    sorted_order[i], sorted_order[i + 1] = sorted_order[i + 1], sorted_order[i]
                    # Update the min/max values
                    if item < min_val:
                        min_val = item
                    if item > max_val:
                        max_val = item
                    break
        elif item > max_val:
            # Swap the current element with the next in the sorted order
            sorted_order[i], sorted_order[i + 1] = sorted_order[i + 1], sorted_order[i]
            # Update the min/max values
            if item < min_val:
                min_val = item
            if item > max_val:
                max_val = item

    # Reverse the list to get the correct order
    return sorted_order[::-1]

