    For example:
    anti_shuffle('Hi') returns 'Hi'
    anti_shuffle('hello') returns 'ehllo'
    anti_shuffle('Hello World!!!') returns 'Hello !!!Wdlor'
    """
    # Split the string into words
    words = s.split()

    # Create a dictionary to store characters and their ASCII values
    char_map = {}

    for char in words:
        if char in char_map:
            char_map[char] += ord(char)
        else:
            char_map[char] = ord(char)

    # Build the new string by concatenating characters in the order of their ASCII values
    new_words = []
    for char in words:
        if char in char_map:
            new_words.append(char_map[char])
        else:
            new_words.append(char)

    return " ".join(new_words)

