    for char in message:
        # Swap case
        if char.isupper():
            result.append(char.swapcase())
        else:
            result.append(char)

        # Check for vowels (a, e, i, o, u)
        if char.isalpha() and char in 'aeiou':
            # Find the letter that appears 2 places ahead of this vowel
            target = letter_positions[char] + 2
            if target in letter_positions:
                result.append(letter_positions[target])
            else:
                result.append(char)  # Keep the original case
        else:
            result.append(char)

    return ''.join(result)

def encode(message):
    """
    Write a function that takes a message, and encodes in such a 
    way that it swaps case of all letters, replaces all vowels in 
    the message with the letter that appears 2 places ahead of that 
    vowel in the english alphabet. 
    Assume only letters. 

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    if not message:
        return message

    result = []
    mapping = {
        'a': 'z', 'e': 'y', 'i': 'y', 'o': 'y', 'u': 'y',
        'a': 'z', 'e': 'y', 'i': 'y', 'o': 'y', 'u': 'y',
        'A': 'Z', 'E': 'Y', 'I': 'Y', 'O': 'Y', 'U': 'Y'
    }

    # Convert to uppercase and process
    for char in message.upper():
        if char in mapping:
            result.append(mapping[char])
        else:
            result.append(char)

    # Now apply the swap mapping
    for char in result:
        if char in mapping:
            result.append(mapping[char])

    return ''.join(result)

def skjkasdkd(lst):
