def tri(n):
    """
    Computes the first n+1 numbers of the Tribonacci sequence based on the provided definition:
    tri(1) = 3
    tri(n) = 1 + n / 2, if n is even.
    tri(n) = tri(n - 1) + tri(n - 2) + tri(n + 1), if n is odd.
    """
    if n <= 1:
        return [3]

    sequence = []
    a, b, c = 3, 1, 0  # tri(1)=3, tri(2)=1, tri(3)=0 (base case for recurrence)

    for _ in range(1, n + 1):
        if _ == 1:
            sequence.append(3)
        elif _ == 2:
            sequence.append(1)
        elif _ == 3:
            sequence.append(0)
        else:
            sequence.append(a + b + c)

        # Update state for next iteration
        if _ == 1:
            a, b, c = 3, 1, 0
        elif _ == 2:
            a, b, c = 1, 1, 0
        else:
            # recurrence: a_new = a_old + b_old + c_old
            a, b, c = b, c, a + b + c

    return sequence

