def is_nested(string):
    '''
    Create a function that takes a string as input which contains only square brackets.
    The function should return True if and only if there is a valid subsequence of brackets 
    where at least one bracket in the subsequence is nested.

    is_nested('[[]]') ➞ True
    is_nested('[]]]]]]][[[[[]') ➞ False
    is_nested('[][]') ➞ False
    is_nested('[]') ➞ False
    is_nested('[[][]]') ➞ True
    is_nested('[[]][[') ➞ True
    '''
    def is_nested_recursive(s, depth, outer_brackets, inner_brackets):
        if not s:
            return False
        char = s[0]
        if char == '(':
            # We expect an opening bracket
            return is_nested_recursive(s[1:], depth + 1, outer_brackets, inner_brackets)
        elif char == ')':
            # We expect a closing bracket
            if depth > 0:
                # If we are still nesting inside, we can't close the outer one yet
                return False
            return is_nested_recursive(s[1:], depth, outer_brackets, inner_brackets)
        else:
            # Unexpected character, but we don't care about it
            return False

    if not string.startswith('['):
        return False
    if not string.endswith(']'):
        return False

    # Count open and closed brackets
    open_count = string.count('(') - string.count(')')
    closed_count = string.count('[') - string.count(']')
    # Since only brackets are present, open = closed only if the sequence is balanced

    if open_count != closed_count:
        return False

    # Check if the outer brackets are properly nested
    # We iterate through the string and keep track of the depth of the outer brackets we are currently building
    outer_depth = 0
    for char in string:
        if char == '[':
            outer_depth += 1
        elif char == ']':
            outer_depth -= 1
            if outer_depth < 0:
                return False
        else:
            return False

    return True

