    fix_spaces("Example") == "Example"
    fix_spaces("Example 1") == "Example_1"
    fix_spaces(" Example 2") == "_Example_2"
    fix_spaces(" Example   3") == "_Example-3"
    """
    def replace_spaces_with_underscore(s):
        return s.replace(" ", "_")

    def replace_consecutive_spaces_with_dash(s):
        result = ""
        i = 0
        while i < len(s):
            if s[i] in " \t\n\r":
                result += s[i]
                i += 1
            else:
                if i + 1 < len(s) and s[i + 1] == " ":
                    # Check if there are more than 2 consecutive spaces
                    if len(s[i+2:]) == 2:
                        result += "-"
                    else:
                        result += " "
                        i += 2
                else:
                    result += s[i]
                    i += 1
        return result

    def replace_all_spaces(text):
        return replace_spaces_with_underscore(text.replace(" ", "_"))

    def replace_consecutive_spaces(text):
        return replace_consecutive_spaces_with_dash(text.replace(" ", "_"))

    def fix_spaces(text):
        result = replace_spaces_with_underscore(text)
        return replace_consecutive_spaces(result)

    return fix_spaces(text)

def fix_spaces(text):
    """
    Given a string text, replace all spaces in it with underscores, 
    and if a string has more than 2 consecutive spaces, 
    then replace all consecutive spaces with - 

    fix_spaces("Example") == "Example"
    fix_spaces("Example 1") == "Example_1"
    fix_spaces(" Example 2") == "_Example_2"
    fix_spaces(" Example   3") == "_Example-3"
    """
    result = []
    if not text:
        return result

    for char in text:
        if char.isspace():
            result.append("_")
        else:
            result.append(char)

    # Check for more than 2 consecutive spaces
    if result[-2:] == " _":
        result[-1] = "-"
    else:
        result[-1] = "_"

    return "".join(result)

def sum_squares(lst):
    """
    This function will take a list of integers. For all entries in the list, the function shall square the integer entry if its index is a 
    multiple of 3 and will cube the integer entry if its index is a multiple of 4 and not a multiple of 3. The function will not 
    change the entries in the list whose indexes are not a multiple of 3 or 4. The function shall then return the sum of all entries. 

    Examples:
    For lst = [1,2,3] the output should be 6
    For lst = []  the output should be 0
    For lst = [-1,-5,2,-1,-5]  the output should be -126
    """
    def is_index_multiple_of(n):
        return lst.index % n == 0

    def calculate(index):
        if is_index_multiple_of(3):
            return lst[index] ** 2
        elif is_index_multiple_of(4):
            return lst[index] ** 3
        else:
            return lst[index]

    return sum(calculate(index) for index in range(len(lst)))

