     Example:
        even_odd_count(-12) ==> (1, 1)
        even_odd_count(123) ==> (1, 2)
    """
    even = 0
    odd = 0

    for digit in str(num):
        if int(digit) % 2 == 0:
            even += 1
        else:
            odd += 1

    return (even, odd)

